+    function monotonicNowMs() {
+        if (typeof performance !== "undefined" && typeof performance.now === "function") {
+            return performance.now();
+        }
+        return Date.now();
+    }
+
+    function emitStructuredLog(level, event, payload = {}) {
+        const body = { event, ...payload };
+        const line = JSON.stringify(body);
+        if (level === "error") console.error(line);
+        else if (level === "warn") console.warn(line);
+        else console.info(line);
+    }
+
+    function nextDependencyAttempt(dep) {
+        const attempt = (DEPENDENCY_ATTEMPTS.get(dep) || 0) + 1;
+        DEPENDENCY_ATTEMPTS.set(dep, attempt);
+        return attempt;
+    }
+
+    function startRenderPass(panel) {
+        const start = monotonicNowMs();
+        emitStructuredLog("info", "spec_viz_render_start", { panel });
+        if (typeof performance !== "undefined" && typeof performance.mark === "function") {
+            try { performance.mark(`spec_viz_render_start:${panel}`); } catch (_e) {}
+        }
+        return start;
+    }
+
+    function finishRenderPass(panel, startedAt, nodeCount) {
+        const durationMs = Math.round(monotonicNowMs() - startedAt);
+        emitStructuredLog("info", "spec_viz_render_finish", {
+            panel,
+            duration_ms: durationMs,
+            node_count: nodeCount,
+        });
+        if (typeof performance !== "undefined" &&
+            typeof performance.mark === "function" &&
+            typeof performance.measure === "function") {
+            try {
+                performance.mark(`spec_viz_render_finish:${panel}`);
+                performance.measure(
+                    `spec_viz_render:${panel}`,
+                    `spec_viz_render_start:${panel}`,
