+    function loadScriptDependency(dep, url) {
+        if (DEPENDENCY_PROMISES.has(dep)) return DEPENDENCY_PROMISES.get(dep);
+
+        const attempt = nextDependencyAttempt(dep);
+        const startedAt = monotonicNowMs();
+        emitStructuredLog("info", "spec_viz_dependency_load_start", { dep, url, attempt });
+
+        const promise = new Promise((resolve, reject) => {
+            const selector = `script[data-spec-viz-dep="${dep}"]`;
+            let script = document.querySelector(selector);
+            if (script && script.dataset.loaded === "true") {
+                emitStructuredLog("info", "spec_viz_dependency_load_finish", {
+                    dep,
+                    url,
+                    attempt,
+                    duration_ms: 0,
