+                    dep,
+                    url,
+                    attempt,
+                    duration_ms: Math.round(monotonicNowMs() - startedAt),
+                });
+                reject(new Error(`Dependency load failed: ${dep}`));
+            };
+
+            script.addEventListener("load", onLoad, { once: true });
+            script.addEventListener("error", onError, { once: true });
+            if (!script.parentNode) document.head.appendChild(script);
+        });
+
+        DEPENDENCY_PROMISES.set(dep, promise);
+        return promise;
+    }
+
